import React from 'react';
import styled from 'styled-components';
import { NavLink } from "react-router-dom";

const SNav = styled.nav`
grid-area:2/1/13/4;
display:flex;
flex-direction:column;
background: #cefefe ;
color:red;
font-family: 'tucsononewoff2';
border: solid 0.2px blue ;
`
const SNavLink = styled(NavLink)`
margin-top:10px;
margin-left:2px;
text-decoration:none;
`



 const Nav = () => {
  return (
<SNav> 

<SNavLink to="/" activeStyle={{
    fontWeight: "bold",
    color: "red"
  }}>дом</SNavLink>

<SNavLink to="/post" activeStyle={{
    fontWeight: "bold",
    color: "red"
  }}> диологи </SNavLink>

  <SNavLink to="/profile" activeStyle={{
    fontWeight: "bold",
    color: "red"
  }}> профиль </SNavLink>

 </SNav>
  );
};


export default Nav;
